198→// Update partially updates an item. Only non-nil fields in input are changed.
199→func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
200→	sets := []string{}
201→	args := []any{ownerID, itemID}
202→	paramIdx := 3
203→
204→	if input.Title != nil {
205→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
206→		args = append(args, *input.Title)
207→		paramIdx++
208→	}
209→	if input.Tags != nil {
210→		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
211→		args = append(args, input.Tags)
212→		paramIdx++
213→	}
214→	if input.Sensitivity != nil {
215→		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
216→		args = append(args, *input.Sensitivity)
217→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
218→	}
219→
220→	if len(sets) == 0 {
221→		return s.GetByID(ctx, ownerID, itemID)
222→	}
223→
224→	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
225→		joinSets(sets), itemColumns)
226→
227→	row := s.pool.QueryRow(ctx, query, args...)
228→	it, err := scanItem(row)
229→	if errors.Is(err, pgx.ErrNoRows) {
230→		return nil, fmt.Errorf("item: update: not found")
231→	}
232→	if err != nil {
233→		return nil, fmt.Errorf("item: update: %w", err)
234→	}
235→	return it, nil
236→}
