 9→// KeyFor generates the S3 key for an item's content.
10→// Pattern: {owner_id}/{type}/{item_id}/{filename}
11→func KeyFor(ownerID uuid.UUID, itemType string, itemID uuid.UUID, filename string) string {
12→	return fmt.Sprintf("%s/%s/%s/%s", ownerID, itemType, itemID, filename)
13→}
