 7→// scanItem scans a single row into an Item.
 8→func scanItem(row pgx.Row) (*Item, error) {
 9→	var it Item
10→	err := row.Scan(
11→		&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
12→		&it.Title, &it.ContentText, &it.ContentURL,
13→		&it.Tags, &it.Metadata, &it.AutoMetadata,
14→		&it.Source, &it.SourceURL,
15→		&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
16→	)
17→	if err != nil {
18→		return nil, err
19→	}
20→	return &it, nil
21→}
22→
23→// scanItems scans multiple rows into a slice of Items.
24→func scanItems(rows pgx.Rows) ([]*Item, error) {
25→	var items []*Item
26→	for rows.Next() {
27→		var it Item
28→		err := rows.Scan(
29→			&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
30→			&it.Title, &it.ContentText, &it.ContentURL,
31→			&it.Tags, &it.Metadata, &it.AutoMetadata,
32→			&it.Source, &it.SourceURL,
33→			&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
34→		)
35→		if err != nil {
36→			return nil, err
37→		}
38→		items = append(items, &it)
39→	}
40→	if err := rows.Err(); err != nil {
41→		return nil, err
42→	}
43→	if items == nil {
44→		items = []*Item{}
45→	}
46→	return items, nil
47→}
